vector<int> numbers(6, 0); // {0, 0, 0, 0, 0, 0}

// "Add 5 to every element from index 1 to 3" — naive: loop indices 1-3, O(range length) PER update
// If asked to apply 1,000 different range updates, that's expensive if ranges are large

vector<int> diff(numbers.size() + 1, 0); // one extra slot at the end

// To add val to every index from l to r (inclusive):
diff[l] += val;
diff[r + 1] -= val;

vector<int> result(numbers.size());
result[0] = diff[0];
for (int i = 1; i < numbers.size(); i++)
{
    result[i] = result[i - 1] + diff[i]; // exactly the Prefix Sum formula
}

#include <iostream>
#include <vector>

using namespace std;

int main()
{
    int n = 6;
    vector<int> diff(n + 1, 0);

    // Add 5 to range [1, 3]
    diff[1] += 5;
    diff[4] -= 5;

    // Add 2 to range [2, 5]
    diff[2] += 2;
    diff[6] -= 2;

    vector<int> result(n);
    result[0] = diff[0];
    for (int i = 1; i < n; i++)
    {
        result[i] = result[i - 1] + diff[i];
    }

    for (int val : result)
    {
        cout << val << " ";
    }

    return 0;
}

