bool carPooling(vector<vector<int>> &trips, int capacity)
{
    vector<int> counts(1001, 0);

    for (auto &t : trips)
    {
        for (int loc = t[1]; loc < t[2]; loc++)
        {
            counts[loc] += t[0];
            if (counts[loc] > capacity) return false;
        }
    }

    return true;
}

