bool isZeroArray(vector<int> &nums, vector<vector<int>> &queries)
{
    int n = nums.size();
    vector<int> coverage(n, 0);

    for (auto &q : queries)
    {
        for (int i = q[0]; i <= q[1]; i++) coverage[i]++;
    }

    for (int i = 0; i < n; i++)
    {
        if (coverage[i] < nums[i]) return false;
    }

    return true;
}

int main()
{
    vector<int> nums = {1, 0, 1};
    vector<vector<int>> queries = {{0, 2}};

    cout << (isZeroArray(nums, queries) ? "true" : "false") << endl;

    return 0;
}

