#include <vector>

using namespace std;

bool isZeroArray(vector<int> &nums, vector<vector<int>> &queries)
{
    int n = nums.size();
    vector<int> diff(n + 1, 0);

    for (auto &q : queries)
    {
        diff[q[0]]++;
        diff[q[1] + 1]--;
    }

    int coverage = 0;
    for (int i = 0; i < n; i++)
    {
        coverage += diff[i];
        if (coverage < nums[i]) return false;
    }

    return true;
}

int main()
{
    vector<int> nums = {1, 0, 1};
    vector<vector<int>> queries = {{0, 2}};

    cout << (isZeroArray(nums, queries) ? "true" : "false") << endl;

    return 0;
}

