using namespace std;

bool feasible(vector<int> &nums, vector<vector<int>> &queries, int k)
{
    int n = nums.size();
    vector<long long> diff(n + 1, 0);

    for (int i = 0; i < k; i++)
    {
        diff[queries[i][0]] += queries[i][2];
        diff[queries[i][1] + 1] -= queries[i][2];
    }

    long long running = 0;
    for (int i = 0; i < n; i++)
    {
        running += diff[i];
        if (running < nums[i]) return false;
    }

    return true;
}

int minZeroArray(vector<int> &nums, vector<vector<int>> &queries)
{
    for (int k = 0; k <= (int)queries.size(); k++)
    {
        if (feasible(nums, queries, k)) return k;
    }
    return -1;
}

int main()
{
    vector<int> nums = {2, 0, 2};
    vector<vector<int>> queries = {{0, 2, 1}, {0, 2, 1}, {1, 1, 3}};

    cout << minZeroArray(nums, queries) << endl;

    return 0;
}

